import{_ as e,o as t,c as i,aw as o}from"./chunks/framework.DLufY-ao.js";const p=JSON.parse('{"title":"Feature-Driven Development (FDD)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/methodology-dev/methodology/fdd.md","filePath":"wiki/dev-commit/theory/methodology-dev/methodology/fdd.md"}'),s={name:"wiki/dev-commit/theory/methodology-dev/methodology/fdd.md"};function a(r,l,d,m,n,u){return t(),i("div",null,[...l[0]||(l[0]=[o('<h1 id="feature-driven-development-fdd" tabindex="-1">Feature-Driven Development (FDD) <a class="header-anchor" href="#feature-driven-development-fdd" aria-label="Permalink to &quot;Feature-Driven Development (FDD)&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Feature-Driven Development</p><ul><li><strong>Feature-Driven Development</strong> (FDD, разработка, управляемая функциональностью)</li><li>Итеративная методология разработки ПО</li><li>Фреймворк Agile для разработки ПО, который организует работу вокруг функций продукта</li><li><em>Особенность</em>: короткие итерации и частые релизы</li><li>Project Business Owner (заказчик) должен присутствовать на первоначальном совещании по проектированию и ретроспективах итераций</li></ul></div><h2 id="виды-деятельности-в-fdd" tabindex="-1">Виды деятельности в FDD <a class="header-anchor" href="#виды-деятельности-в-fdd" aria-label="Permalink to &quot;Виды деятельности в FDD&quot;">​</a></h2><details class="details custom-block"><summary>1. Разработка общей модели</summary><p><strong>Описание</strong></p><ul><li>Общая модель создается главным архитектором или другим специалистом, руководящим проектом, путем определения области действия и контекста системы.</li></ul><p><strong>Алгоритм</strong></p><ol><li>Высокоуровневневый сквозной анализ широты решаемого круга задач и контекста системы</li><li>Для каждой моделируемой области делается более детальный сквозной анализ. Сквозные описания составляются в небольших группах и выносятся на дальнейшее обсуждение и экспертную оценку</li><li>Одна из предлагаемых моделей или их объединение становится моделью для конкретной области. Модели каждой области задач объединяются в общую итоговую модель, которая изменяется в ходе работы</li></ol></details><details class="details custom-block"><summary>2. Составление списка необходимых функций системы</summary><p><strong>Описание</strong></p><ul><li>Разработчики проводят мозговой штурм списка потенциальных элементов, которые будут полезны пользователям и могут быть завершены в установленные сроки для выпуска. Каждая функция должна быть управляемой в течение примерно двух недель</li></ul><p><strong>Правила</strong></p><ul><li>Разбиение областей (domain) на предметные области (subject areas) с точки зрения функциональности</li><li>Каждая отдельная подобласть соответствует какому-либо бизнес-процессу, шаги которого становятся списком функций (свойств). В данном случае функции - это маленькие части понимаемых пользователем функций, представленных в виде &quot;действие - результат - объект&quot;, например, «проверка пароля пользователя»</li><li>Разработка каждой функции должна занимать не более 2 недель, иначе задачу необходимо разбить на несколько подзадач, каждая из которых сможет быть завершена за установленный двухнедельный срок</li></ul></details><details class="details custom-block"><summary>3. Планирование работы над каждой функцией</summary><p><strong>Описание</strong></p><ul><li>Владение классами распределяется среди ведущих программистов путём упорядочивания и организации свойств (или наборов свойств) в классы</li><li>Функции организованы по времени их создания и важности для клиента. Назначается право собственности на каждую функцию</li></ul></details><details class="details custom-block"><summary>4. Проектирование функции</summary><p><strong>Описание</strong></p><ul><li>Детали каждой функции производятся, проверяются и дорабатываются</li></ul><p><strong>Алгоритм</strong></p><ol><li>Для каждого свойства создается проектировочный пакет</li><li>Ведущий программист выделяет небольшую группу свойств для разработки в течение двух недель</li><li>Вместе с разработчиками соответствующего класса ведущий программист составляет подробные диаграммы последовательности для каждого свойства, уточняя общую модель</li><li>Пишутся «заготовки» классов и методов, и происходит критическое рассмотрение дизайна</li></ol></details><details class="details custom-block"><summary>5. Реализация функции</summary><p><strong>Алгоритм</strong></p><ol><li>После успешного рассмотрения дизайна данная видимая клиенту функциональность реализуется до состояния готовности</li><li>Для каждого класса пишется программный код</li><li>После модульного тестирования каждого блока и проверки кода завершенная функция включается в основной проект (build)</li></ol></details>',8)])])}const g=e(s,[["render",a]]);export{p as __pageData,g as default};
